function mdToHtml(text) {
  let out = text ?? '';

  // ul/li в bullets: "* " или "- " в начале строки
  out = out.replace(/^(?:\*|-) +/gm, '• ');

  // Markdown-ссылки [текст](url) -> <a href="url">текст</a>
  out = out.replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/gi, '<a href="$2">$1</a>');

  // ***bold+italic*** -> <em><strong>…</strong></em>
  out = out.replace(/\*\*\*([^\*]+?)\*\*\*/g, '<em><strong>$1</strong></em>');

  // **bold** -> <strong>…</strong>
  out = out.replace(/\*\*([^*<>]+?)\*\*/g, '<strong>$1</strong>');

  // *italic* -> <em>…</em> (не трогаем внутри тегов)
  out = out.replace(/(?<![^<]*>)\*([^*<>]+?)\*(?![^<]*>)/g, '<em>$1</em>');

  return out;
}

function sanitizeTelegramHtml(html) {
  // Разрешённые теги Telegram + strong/em
  const allowed = new Set(['b','strong','i','em','u','s','code','pre','a','tg-spoiler','blockquote']);

  // Никакой нормализации strong/em — оставляем как есть

  // Удаляем все атрибуты у разрешённых тегов, кроме href у <a>
  html = html.replace(/<(\/?)([a-z0-9-]+)([^>]*)>/gi, (m, slash, tag, attrs) => {
    tag = tag.toLowerCase();

    if (!allowed.has(tag)) {
      return ''; // выкидываем чужие теги полностью
    }
    if (slash) return `</${tag}>`;

    if (tag === 'a') {
      const hrefMatch = attrs.match(/href\s*=\s*"([^"]+)"/i) || attrs.match(/href\s*=\s*'([^']+)'/i);
      const href = hrefMatch ? hrefMatch[1].trim() : '';
      if (!/^https?:\/\//i.test(href)) return '<a href="#">';
      return `<a href="${href}">`;
    }

    return `<${tag}>`;
  });

  // Конвертируем <ul><li>…</li></ul> в буллеты
  html = html.replace(/<ul[\s\S]*?>[\s\S]*?<\/ul>/gi, (m) => {
    const items = m.match(/<li[\s\S]*?>([\s\S]*?)<\/li>/gi) || [];
    const lines = items.map(li => '• ' + li.replace(/<\/?li[^>]*>/gi, '').trim());
    return lines.join('\n');
  });

  // Чистим лишние пробелы и пустые строки
  html = html
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return html;
}

function splitTelegramMessage(html, maxLen = 4096) {
  const tagRegex = /<\/?([a-z0-9-]+)[^>]*>/gi;
  const openTags = [];
  const chunks = [];
  let current = '';

  const pushChunk = () => {
    let tail = '';
    for (let i = openTags.length - 1; i >= 0; i--) tail += `</${openTags[i]}>`;
    chunks.push((current + tail).trim());
  };

  const reopenForNext = () => {
    current = openTags.map(t => `<${t}>`).join('');
  };

  // Разбиваем по безопасным границам
  const parts = html.split(/(\n\n|<\/blockquote>|<\/pre>|<\/code>)/);

  for (const part of parts) {
    if (!part) continue;

    // Обновляем стек открытых тегов на основании текущей части
    let temp = part;
    let m;
    while ((m = tagRegex.exec(temp))) {
      const full = m[0];
      const tag = (m[1] || '').toLowerCase();

      if (!['b','strong','i','em','u','s','code','pre','a','tg-spoiler','blockquote'].includes(tag)) continue;

      if (full.startsWith('</')) {
        const idx = openTags.lastIndexOf(tag);
        if (idx !== -1) openTags.splice(idx, 1);
      } else if (!full.endsWith('/>')) {
        // Для <a> следим, чтобы был закрывающий </a> в этой же части, иначе считаем открытым
        if (tag !== 'a' || !(/<\/a>/i.test(temp))) {
          openTags.push(tag);
        }
      }
    }

    const closingTail = openTags.slice().reverse().map(t => `</${t}>`).join('');
    if ((current + part + closingTail).length > maxLen) {
      if (current) pushChunk();
      reopenForNext();

      if ((current + part + closingTail).length > maxLen) {
        // Грубое деление по символам с сохранением открытых тегов
        let p = part;
        while (p.length) {
          const remainClosing = openTags.slice().reverse().map(t => `</${t}>`).join('');
          const spaceLeft = maxLen - (current.length + remainClosing.length);
          current += p.slice(0, Math.max(spaceLeft, 0));
          p = p.slice(Math.max(spaceLeft, 0));
          pushChunk();
          reopenForNext();
        }
      } else {
        current += part;
      }
    } else {
      current += part;
    }
  }

  if (current.trim()) pushChunk();
  return chunks.filter(Boolean);
}

