function detectEncoding(buf) {
  // BOM check
  if (buf[0] === 0xEF && buf[1] === 0xBB && buf[2] === 0xBF) {
    return 'utf-8';
  }

  // Heuristic: check Cyrillic chars frequency
  const textSample = buf.toString('latin1', 0, 1000); // raw bytes
  const cyrillicCount = (textSample.match(/[А-Яа-яЁё]/g) || []).length;
  const asciiCount = (textSample.match(/[A-Za-z]/g) || []).length;

  if (cyrillicCount > asciiCount) {
    return 'win1251'; // assume Windows-1251
  }

  return 'utf-8'; // default
}

function decodeBuffer(buf, encoding) {
  if (encoding === 'utf-8') {
    return buf.toString('utf-8');
  }
  if (encoding === 'win1251') {
    // manual mapping for Windows-1251
    const iconvMap = {
      0xC0: 'А', 0xC1: 'Б', 0xC2: 'В', 0xC3: 'Г', 0xC4: 'Д', 0xC5: 'Е', 0xC6: 'Ж', 0xC7: 'З', 0xC8: 'И', 0xC9: 'Й',
      0xCA: 'К', 0xCB: 'Л', 0xCC: 'М', 0xCD: 'Н', 0xCE: 'О', 0xCF: 'П', 0xD0: 'Р', 0xD1: 'С', 0xD2: 'Т', 0xD3: 'У',
      0xD4: 'Ф', 0xD5: 'Х', 0xD6: 'Ц', 0xD7: 'Ч', 0xD8: 'Ш', 0xD9: 'Щ', 0xDA: 'Ъ', 0xDB: 'Ы', 0xDC: 'Ь', 0xDD: 'Э',
      0xDE: 'Ю', 0xDF: 'Я',
      0xE0: 'а', 0xE1: 'б', 0xE2: 'в', 0xE3: 'г', 0xE4: 'д', 0xE5: 'е', 0xE6: 'ж', 0xE7: 'з', 0xE8: 'и', 0xE9: 'й',
      0xEA: 'к', 0xEB: 'л', 0xEC: 'м', 0xED: 'н', 0xEE: 'о', 0xEF: 'п', 0xF0: 'р', 0xF1: 'с', 0xF2: 'т', 0xF3: 'у',
      0xF4: 'ф', 0xF5: 'х', 0xF6: 'ц', 0xF7: 'ч', 0xF8: 'ш', 0xF9: 'щ', 0xFA: 'ъ', 0xFB: 'ы', 0xFC: 'ь', 0xFD: 'э',
      0xFE: 'ю', 0xFF: 'я'
    };
    return buf.toString('latin1').split('').map(ch => {
      const code = ch.charCodeAt(0);
      return iconvMap[code] || ch;
    }).join('');
  }
  return buf.toString('utf-8'); // fallback
}

